var semiOrderedPermutation = function(nums) {
    const n = nums.length;
    const i = nums.indexOf(1);
    const j = nums.indexOf(n);
    let swaps = i + (n - 1 - j);
    if (i > j) swaps -= 1;
    return swaps;
};
